import java.util.ArrayList;
import java.util.List;

public int dfs(int node, int parent, int[] nums, List<List<Integer>> graph, int total, int[] result) {
    int sum = nums[node];
    for (int neighbor : graph.get(node)) {
        if (neighbor != parent) {
            sum += dfs(neighbor, node, nums, graph, total, result);
        }
    }
    if (sum == total / 2) {
        result[0]++;
        return 0;
    }
    return sum;
}

public int delete_edges_to_balance_tree(int[] nums, int[][] edges) {
    int n = nums.length;
    List<List<Integer>> graph = new ArrayList<>();
    for (int i = 0; i < n; i++) {
        graph.add(new ArrayList<>());
    }
    for (int[] e : edges) {
        graph.get(e[0]).add(e[1]);
        graph.get(e[1]).add(e[0]);
    }

    int total = 0;
    for (int num : nums) {
        total += num;
    }
    if (total % 2 != 0) {
        return 0;  // It is impossible to split the tree fairly.
    }

    int[] result = {0};
    dfs(0, -1, nums, graph, total, result);
    return result[0] - 1;
}
```

    The algorithm includes the following steps:

1. Build a graph representing the tree, where each node has an array of its adjacent nodes.
2. Calculate the total sum of the values in `nums`.
3. If the total sum is not divisible by 2, return 0 since it is impossible to divide the tree into components with the same value.
4. Perform a Depth-First Search (DFS) from node 0, traversing through the tree and calculating the subtree sums while keeping track of how many subtree sums we have seen that are half of the total sum.
5. Return the number of subtree sums that are half of the total sum minus 1, since we have to remove one additional component (the whole tree).

The time complexity of the algorithm is O(n), as we traverse each node in the tree once during the DFS.
